diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..d63fee7719d7 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4629,7 +4629,74 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
     if (match(TrueVal, m_ZeroInt()))
       return ConstantInt::getFalse(Cond->getType());
   }
-
+  // select (select X, Y, false), true, Y --> Y
+  // select (select X, false, Y), true, Y --> Y
+  // select (select Y, X, false), true, Y --> Y
+  // select (select Y, false, X), true, Y --> Y
+  if (match(TrueVal, m_One())) {
+    Value *X;
+    if (match(Cond, m_Select(m_Value(X), m_Specific(FalseVal), m_ZeroInt())) ||
+        match(Cond, m_Select(m_Value(X), m_ZeroInt(), m_Specific(FalseVal))) ||
+        match(Cond, m_Select(m_Specific(FalseVal), m_Value(X), m_ZeroInt())) ||
+        match(Cond, m_Select(m_Specific(FalseVal), m_ZeroInt(), m_Value(X))))
+      return FalseVal;
+  }
+  // select Y, true, (select X, Y, false) --> Y
+  // select Y, true, (select Y, X, false) --> Y
+  // select Y, true, (select X, false, Y) --> Y
+  // select Y, true, (select Y, false, X) --> Y
+  if (match(TrueVal, m_One())) {
+    Value *X;
+    if (match(FalseVal, m_Select(m_Value(X), m_Specific(Cond), m_ZeroInt())) ||
+        match(FalseVal, m_Select(m_Specific(Cond), m_Value(X), m_ZeroInt())) ||
+        match(FalseVal, m_Select(m_Value(X), m_ZeroInt(), m_Specific(Cond))) ||
+        match(FalseVal, m_Select(m_Specific(Cond), m_ZeroInt(), m_Value(X))))
+      return Cond;
+  }
+  // select (select X, true, Y), Y, false --> Y
+  // select (select X, Y, true), Y, false --> Y
+  // select (select Y, true, X), Y, false --> Y
+  // select (select Y, X, true), Y, false --> Y
+  if (match(FalseVal, m_ZeroInt())) {
+    Value *X;
+    if (match(Cond, m_Select(m_Value(X), m_One(), m_Specific(TrueVal))) ||
+        match(Cond, m_Select(m_Value(X), m_Specific(TrueVal), m_One())) ||
+        match(Cond, m_Select(m_Specific(TrueVal), m_One(), m_Value(X))) ||
+        match(Cond, m_Select(m_Specific(TrueVal), m_Value(X), m_One())))
+      return TrueVal;
+  }
+  // select Y, (select X, true, Y), false --> Y
+  // select Y, (select Y, true, X), false --> Y
+  // select Y, (select X, Y, true), false --> Y
+  // select Y, (select Y, X, true), false --> Y
+  if (match(FalseVal, m_ZeroInt())) {
+    Value *X;
+    if (match(TrueVal, m_Select(m_Value(X), m_One(), m_Specific(Cond))) ||
+        match(TrueVal, m_Select(m_Specific(Cond), m_One(), m_Value(X))) ||
+        match(TrueVal, m_Select(m_Value(X), m_Specific(Cond), m_One())) ||
+        match(TrueVal, m_Select(m_Specific(Cond), m_Value(X), m_One())))
+      return Cond;
+  }
+  // select X, true, (and X, Y) --> X
+  // select X, true, (and Y, X) --> X
+  if (match(TrueVal, m_One()) &&
+      match(FalseVal, m_c_And(m_Specific(Cond), m_Value())))
+    return Cond;
+  // select (and X, Y), true, X --> X
+  // select (and Y, X), true, X --> X
+  if (match(TrueVal, m_One()) &&
+      match(Cond, m_c_And(m_Specific(FalseVal), m_Value())))
+    return FalseVal;
+  // select X, (or X, Y), false --> X
+  // select X, (or Y, X), false --> X
+  if (match(FalseVal, m_ZeroInt()) &&
+      match(TrueVal, m_c_Or(m_Specific(Cond), m_Value())))
+    return Cond;
+  // select (or X, Y), X, false --> X
+  // select (or Y, X), X, false --> X
+  if (match(FalseVal, m_ZeroInt()) &&
+      match(Cond, m_c_Or(m_Specific(TrueVal), m_Value())))
+    return TrueVal;
   // If the true or false value is poison, we can fold to the other value.
   // If the true or false value is undef, we can fold to the other value as
   // long as the other value isn't poison.

